2787	\begin{lemma}[Pullback of sheaves of modules along a morphism of schemes]
2788	  \label{lem:modules_pullback_mathlib}
2789	  \lean{AlgebraicGeometry.Scheme.Modules.pullback}
2790	  \mathlibok
2791	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
2792	  For a morphism of schemes \(f : X \to Y\), Mathlib supplies the pullback functor
2793	  \(f^{*} : Y.\mathrm{Modules} \to X.\mathrm{Modules}\) on sheaves of modules, left adjoint to
2794	  pushforward, hence colimit-preserving, and carrying the unit sheaf to the unit sheaf. The project
2795	  already uses this functor in the definition of local freeness. It is the geometric restriction
2796	  through which a presentation is transported to an open subscheme.
2797	\end{lemma}
2798	
2799	\begin{lemma}[Restriction of sheaves of modules along an open immersion]
2800	  \label{lem:modules_restrictFunctor_mathlib}
2801	  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctor}
2802	  \mathlibok
2803	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
2804	  For an open immersion \(f : X \to Y\), Mathlib supplies the restriction functor
2805	  \(f^{\mathrm{res}} : Y.\mathrm{Modules} \to X.\mathrm{Modules}\), with
2806	  \(\Gamma(f^{\mathrm{res}} M, U) = \Gamma(M, f(U))\) definitionally; it is a left adjoint (colimit
2807	  preserving) and carries the unit sheaf to the unit sheaf. This is the geometric
2808	  ``restrict to open \(U\)'' functor on \((\Spec R).\mathrm{Modules}\).
2809	\end{lemma}
2810	
2811	\begin{lemma}[Restriction is isomorphic to pullback]
2812	  \label{lem:modules_restrictFunctorIsoPullback_mathlib}
2813	  \lean{AlgebraicGeometry.Scheme.Modules.restrictFunctorIsoPullback}
2814	  \mathlibok
2815	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
2816	  For an open immersion \(f\), the restriction functor (\cref{lem:modules_restrictFunctor_mathlib})
2817	  is naturally isomorphic to the pullback functor (\cref{lem:modules_pullback_mathlib}):
2818	  \(f^{\mathrm{res}} \cong f^{*}\). This identifies the restriction functor with the
2819	  universal-property pullback, so a presentation transported along one transports along the other.
2820	\end{lemma}
