2837	\begin{lemma}[Slice-presentation transport for quasi-coherence data]
2838	  \label{lem:quasicoherentData_bind_mathlib}
2839	  \lean{SheafOfModules.QuasicoherentData.bind}
2840	  \mathlibok
2841	  \textit{Provided by Mathlib (\texttt{Mathlib.Algebra.Category.ModuleCat.Sheaf.Quasicoherent}).}
2842	  Mathlib's \(\mathrm{QuasicoherentData.bind}\) transports a presentation across an iterated
2843	  Grothendieck slice: from quasi-coherence data on a cover \(\{X_i\}\) and, for each \(i\), data on a
2844	  cover of \(M.\mathrm{over}\,X_i\), it assembles quasi-coherence data on the composite cover, by
2845	  applying \(\mathrm{Presentation.map}\) (\cref{lem:presentation_map_mathlib}) along the equivalence
2846	  \(\mathrm{pushforwardPushforwardEquivalence}(\mathrm{Over.iteratedSliceEquiv}\,\cdots)\). It is the
2847	  worked template for the per-element presentation transport used in \cref{lem:over_restrict_iso} and
2848	  \cref{lem:isIso_fromTildeΓ_basicOpen_of_quasicoherent}, handling the slice-site adjointness and
2849	  sheafification typeclass synthesis.
2850	\end{lemma}
